    11→    this._reconnectTimer = null
    12→    this._queue = []
    13→    this._reconnectDelay = 3000
    14→  }
    15→
    16→  connect(token) {
    17→    this._token = token
    18→    this._running = true
    19→    this._doConnect()
    20→  }
    21→
    22→  _doConnect() {
    23→    if (!this._running) return
    24→    const url = WS_URL.replace('{token}', encodeURIComponent(this._token))
    25→    try {
    26→      this._ws = new WebSocket(url)
    27→
    28→      this._ws.onopen = () => {
    29→        this._reconnectDelay = 3000
    30→        this._queue.forEach(msg => this._ws.send(JSON.stringify(msg)))
    31→        this._queue = []
    32→        this.onConnect?.()
    33→      }
    34→
    35→      this._ws.onmessage = (e) => {
    36→        try {
    37→          const data = JSON.parse(e.data)
    38→          this.onMessage?.(data)
    39→        } catch {}
    40→      }
    41→
    42→      this._ws.onerror = () => {}
    43→
    44→      this._ws.onclose = () => {
    45→        this._ws = null
    46→        if (this._running) {
    47→          this.onDisconnect?.()
    48→          this._reconnectTimer = setTimeout(() => {
    49→            this._reconnectDelay = Math.min(this._reconnectDelay * 1.5, 30000)
    50→            this._doConnect()
    51→          }, this._reconnectDelay)
    52→        }
    53→      }
    54→    } catch (err) {
    55→      if (this._running) {
    56→        this._reconnectTimer = setTimeout(() => this._doConnect(), this._reconnectDelay)
    57→      }
    58→    }
    59→  }
    60→
